mapper.select:
select A.USER_ID , A.USER_UUID , A.USER_NM , A.USER_GB , A.PHONE , A.GENDER , A.BIRTH , A.JOIN_YMD , A.HEIGHT , A.WEIGHT , IFNULL(A.EMAIl,'') AS EMAIl , IFNULL(B.DTL_CODE_NM,'') AS DTL_CODE_NM , A.REG_DTM From T_USER_TRAN A LEFT OUTER JOIN T_COMM_MST_DTL B ON B.CODE = 'CD7' AND B.DTL_CODE = A.BLOD_GB where 1=1 AND USER_GB = #{user_gb}
AND (A.USER_NM LIKE CONCAT('%',#{user_nm},'%') OR A.PHONE LIKE CONCAT('%',#{user_nm},'%'))
Order by A.REG_DTM ,A.USER_NM, A.PHONE

mapper.insert:

insert into T_USER_TRAN
	(
	  USER_NM
	, USER_ID
	, USER_PW
	, PHONE
	, BIRTH
	, GENDER
	, EMAIL
	, REG_DTM
	, USER_GB
	, LOCK_YN
	)
	values
	(
	  #{user_nm}
	, #{user_id}
	, #{user_pw}
	, #{phone}
	, #{birth}
	, #{gender}
	, #{email}
	, NOW()
	, DATE_FORMAT(now(),'%Y%m%d')
	, 'p'
	, 'N'
	)

mapper.update:
update T_USER_TRAN
   set PHONE   = #{phone}
     , EMAIL   = #{email}
	 , USER_PW = #{user_pw}
	 , USER_NM = #{user_nm}
 where 1=1
   and USER_ID = #{user_id}
   and GENDER  = #{gender}
   and BIRTH   = #{birth}
